#include <hexi/endian.h>
#include <cstdint>

template<hexi::endian::conversion conv, typename T>
T convert_with_enum(T value) {
    if constexpr (conv == hexi::endian::conversion::big_to_native) {
        return hexi::endian::be(value).from();
    } else if constexpr (conv == hexi::endian::conversion::native_to_big) {
        return hexi::endian::be(value).to();
    } else if constexpr (conv == hexi::endian::conversion::little_to_native) {
        return hexi::endian::le(value).from();
    } else if constexpr (conv == hexi::endian::conversion::native_to_little) {
        return hexi::endian::le(value).to();
    } else {
        // Handle unknown conversion type (should not happen with valid enum)
        return value;
    }
}
```

**Explanation:**

1. **Template Parameter Usage**: The function uses the `conv` template parameter to determine which endianness conversion to perform at compile time.

2. **Conditional Compilation**: `if constexpr` statements allow the compiler to evaluate the condition at compile time, ensuring optimal performance by only including the relevant code path.

3. **Endian Adaptor Selection**: Based on the enum value:
   - `big_to_native`: Uses `hexi::endian::be(value).from()` to convert from big endian to native
   - `native_to_big`: Uses `hexi::endian::be(value).to()` to convert from native to big endian  
   - `little_to_native`: Uses `hexi::endian::le(value).from()` to convert from little endian to native
   - `native_to_little`: Uses `hexi::endian::le(value).to()` to convert from native to little endian

4. **Error Handling**: The final `else` clause handles any unexpected enum values by returning the original value.

This implementation efficiently handles all four required endianness conversions using the Hexi library's endian adaptor system while maintaining type safety through template constraints.

