uint32_t read_uint32_from_file(const std::filesystem::path& file_path) {
    // Create a file_buffer object with the given file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer is in a valid state
    if (!buffer) {
        throw std::runtime_error("Failed to open file or file is empty");
    }

    // Use the read<uint32_t>() method to read the value
    uint32_t value;
    buffer.read<uint32_t>(&value);

    // Return the read value
    return value;
}

void write_uint32_to_file(const std::filesystem::path& file_path, uint32_t value) {
    // Create a file_buffer object with the given file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer is in a valid state
    if (!buffer) {
        throw std::runtime_error("Failed to open file for writing");
    }

    // Use the write<uint32_t>() method to write the value
    buffer.write<uint32_t>(value);

    // Flush to ensure data is written to disk
    buffer.flush();
}
```

