    // Check if the requested number of bytes to preview exceeds the available data in the buffer
    if (bytes_to_preview > buffer.size()) {
        // Handle appropriately by throwing an exception
        throw std::out_of_range("Preview request exceeds available data in buffer");
    }

    // Create a destination vector with the required size
    std::vector<uint8_t> destination(bytes_to_preview);

    // Use the copy method of the static_buffer to copy data without advancing the read pointer
    buffer.copy(destination.data(), bytes_to_preview);

    return destination;
}
```

