    hexi::binary_stream<std::vector<uint8_t>> stream(buffer);

    // Convert message_id from native to big-endian and write
    uint32_t big_message_id = hexi::endian::native_to_big(packet.message_id);
    stream.write(big_message_id);

    // Convert each element in data_values from native to big-endian and write container
    std::vector<uint16_t> big_data_values;
